-- Seed data generated from 'Info for tutor registration tool.xlsx' (groups/times)
-- and '2026-2027 MSP Course Catalogue April.pdf' (coordinators, descriptions, prerequisites).
-- Safe to re-run: rebuilds the catalogue. Leaves live tutor registrations untouched
-- (only the pre-assigned ones it manages are re-seeded). Run AFTER schema.sql.
begin;
delete from registration where tutor_type = 'Pre-assigned';
delete from tutorial_group;
delete from course;


-- Tutorial groups

-- Pre-assigned tutors -> seeded as confirmed so their groups show as filled
commit;
